const rawMessage = $json.message;
const rawRoom = $json.room;
const rawMsgtype = $json.msgtype;
const rawAccessToken = $json.accessToken;

const message = typeof rawMessage === 'string' ? rawMessage.trim() : '';
const room = typeof rawRoom === 'string' ? rawRoom.trim() : '';
const msgtype = typeof rawMsgtype === 'string' && rawMsgtype.trim() ? rawMsgtype.trim() : 'm.text';
const accessToken = typeof rawAccessToken === 'string' ? rawAccessToken.trim() : '';

return [{
  json: {
    message,
    room,
    msgtype,
    accessToken
  }
}];

const normalized = $('Normalize input').item.json || {};
const config = $('Set Matrix config').item.json || {};

const message = typeof normalized.message === 'string' ? normalized.message.trim() : '';
const inputRoom = typeof normalized.room === 'string' ? normalized.room.trim() : '';
const msgtype = typeof normalized.msgtype === 'string' && normalized.msgtype.trim() ? normalized.msgtype.trim() : 'm.text';
const inputAccessToken = typeof normalized.accessToken === 'string' ? normalized.accessToken.trim() : '';

const homeserverUrlRaw = typeof config.homeserverUrl === 'string' ? config.homeserverUrl.trim() : '';
const defaultRoomRaw = typeof config.defaultRoom === 'string' ? config.defaultRoom.trim() : '';
const fallbackAccessTokenRaw = typeof config.fallbackAccessToken === 'string' ? config.fallbackAccessToken.trim() : '';

const usedHomeserverUrl = homeserverUrlRaw.replace(/\/+$/, '');
const usedRoom = inputRoom || defaultRoomRaw;
const resolvedFallbackToken = inputAccessToken || fallbackAccessTokenRaw;
const hasFallbackToken = !!resolvedFallbackToken;
const txnId = `n8n-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;

let error = '';
if (!message) {
  error = 'Input field message is required and must be a non-empty string.';
} else if (!usedRoom) {
  error = 'No room configured. Pass room or set defaultRoom in node Set Matrix config.';
} else if (!usedHomeserverUrl) {
  error = 'No homeserver URL configured. Set homeserverUrl in node Set Matrix config.';
}

const requestUrl = !error
  ? `${usedHomeserverUrl}/_matrix/client/v3/rooms/${encodeURIComponent(usedRoom)}/send/m.room.message/${encodeURIComponent(txnId)}`
  : '';

return [{
  json: {
    message,
    msgtype,
    usedRoom,
    usedHomeserverUrl,
    resolvedFallbackToken,
    hasFallbackToken,
    txnId,
    requestUrl,
    okToSend: !error,
    error
  }
}];

const response = $json || {};
const statusCode = Number(response.statusCode || response.code || 0) || null;
const hasError = !!response.error || !!response.message || !!response.errcode || (statusCode !== null && statusCode >= 400);
const ok = !hasError && (statusCode === null || (statusCode >= 200 && statusCode < 300));
const resolved = $('Resolve and validate payload').item.json || {};

return [{
  json: {
    ok,
    statusCode,
    usedRoom: resolved.usedRoom || null,
    usedHomeserverUrl: resolved.usedHomeserverUrl || null,
    usedAuth: 'credential',
    response
  }
}];

const response = $json || {};
const statusCode = Number(response.statusCode || response.code || 0) || null;
const hasError = !!response.error || !!response.message || !!response.errcode || (statusCode !== null && statusCode >= 400);
const ok = !hasError && (statusCode === null || (statusCode >= 200 && statusCode < 300));
const resolved = $('Resolve and validate payload').item.json || {};

return [{
  json: {
    ok,
    statusCode,
    usedRoom: resolved.usedRoom || null,
    usedHomeserverUrl: resolved.usedHomeserverUrl || null,
    usedAuth: resolved.hasFallbackToken ? 'fallbackToken' : 'none',
    response
  }
}];

const credentialResult = $('Evaluate credential attempt').item.json || {};
const fallbackResult = $('Evaluate fallback attempt').item.json || {};
const resolved = $('Resolve and validate payload').item.json || {};

const credentialMessage = credentialResult.response?.error || credentialResult.response?.message || credentialResult.response?.errcode || 'unknown credential error';
const fallbackMessage = fallbackResult.response?.error || fallbackResult.response?.message || fallbackResult.response?.errcode || 'unknown fallback error';
const fallbackMode = resolved.hasFallbackToken ? 'fallback token' : 'no auth';

throw new Error(`Matrix send failed. Credential attempt failed (${credentialMessage}). Fallback attempt (${fallbackMode}) failed (${fallbackMessage}).`);
